INSERT INTO `tooldetail` (`id`, `name`, `category`, `price`, `pros`, `description`, `source`, `image_path`, `is_remote`) VALUES
(1, 'VIVOSUN Digital pH Meter', 'pH', '9.95', 'Best Budget', 'Brand & Model: VIVOSUN pH Meter\r\n\r\nAccuracy: ±0.1 pH\r\n\r\nResolution: 0.01 pH\r\n\r\nMeasuring range: 0.00 to 14.00 pH\r\n\r\nOperation temperature: 0°C to 60°C (32°F to 140°F)\r\n\r\nSize: 6.3 x 1.2 x 0.8 inches (16 x 3 x 2 cm)\r\n\r\nPros: \r\n-Easy to use\r\n-Equipped with auto-calibration functionality\r\n-Automatic Temperature Compensation (ATC)\r\n-Compact and portable\r\n-Backlit display for better visibility in low light\r\n-Auto-off feature to save battery\r\n\r\nCons: \r\n-The battery life might deplete quickly, especially with the backlight on.\r\n-May require regular calibration to maintain accuracy.', 'https://www.amazon.com/VIVOSUN-Meter-Digital-Tester-Water/dp/B01M5IASHD/ref=sr_1_3?crid=4YDJTWG4LVCX&dib=eyJ2IjoiMSJ9.53O0n1YgD32E_Eff2TdG857JoMODAfeDs_zTkR6VdemzVZkjRjoEQjdQDBxCwT6w6ctw40loqW9w-32kYXK4AP0KJB0QvHhvH7bz-rjlRbhPTrww2pzhLjil8Z_gvxBBifwvRpjZMnnreBRKNs8mKuUQoTqJBPxsKeZ0aZ6296TZgMm3yuYDOwbXkNb0gCKV6s4EwkyjIGKhPWVswlu3F2y2c_ArrYhRleCnW0HhEM4.7UngPWPgIBRCOTLiikav5d17WUWG49_geavEatnENFo&dib_tag=se&keywords=vivosun%2Bph&qid=1725530704&sprefix=vivosunp%2Caps%2C443&sr=8-3&th=1', 'image1', 0),
(2, 'Apera Digital pH Meter', 'pH', '40.93', 'Best Overall', 'Brand & Model: APERA INSTRUMENTS AI209 Value Series pH20 Waterproof pH Tester Kit\n\nAccuracy: ±0.1 pH\n\nResolution: 0.01 pH\n\nMeasuring range: 0.00 to 14.00 pH\n\nOperation temperature: 0°C to 50°C (32°F to 122°F)\n\nSize: 7.01 x 1.61 x 1.18 inches (17.8 x 4.0 x 3.0 cm)\n\nPros:\n-Waterproof design, suitable for use in various environments\n-Easy calibration with one-touch auto-calibration\n-Clear and easy-to-read LCD display\n-Durable and rugged build, ideal for fieldwork\n-Automatic Temperature Compensation (ATC) for accurate readings\n-Long battery life with auto-off feature\n-Generally priced competitively, offering good value for the features\n\nCons:\n-May require frequent calibration depending on usage\n-Slightly bulkier than some compact models', 'https://www.amazon.com/dp/B01ENFOHN8?tag=plumbingshower-20&th=1', 'image2', 0),
(3, 'Apera Instruments Premium-Series PH60S', 'pH', '185.54', 'Best Premium', 'Brand & Model: Apera Instruments Premium-Series PH60S Food pH Pocket Tester Kit, Swiss Spear pH Electrode (AI313)\r\n\r\nAccuracy: ±0.01 pH\r\n\r\nResolution: 0.01 pH\r\n\r\nMeasuring range: -2.00 to 16.00 pH\r\n\r\nOperation temperature: 0°C to 50°C (32°F to 122°F)\r\n\r\nSize: 7 x 1.6 x 1.6 inches (17.8 x 4.1 x 4.1 cm)\r\n\r\nPros:\r\n-High accuracy with ±0.01 pH precision\r\n-Swiss spear sensor with long-life reference system\r\n-Easy automatic calibration with up to 3 points and auto temperature compensation (ATC)\r\n-Wider range for pH measurement.\r\n-Unique high/low value alarm function with red backlight for immediate attention to results\r\n-Large clear LCD with 3 backlit colors, displaying both temperature and pH, and indications for calibration and stable readings\r\n-Complete kit with calibration solutions, bottles, storage solutions, AAA batteries, and a carrying case\r\n-CE and RoHS certified, manufactured under ISO 9001:2015 quality system\r\n-Competitive price for high-end features and durable build\r\n\r\nCons:\r\n-Higher price point compared to some basic models\r\n-Regular calibration may be necessary to maintain accuracy\r\n-Slightly bulkier than some compact models', 'https://www.amazon.com/Apera-Instruments-Replaceable-Accuracy-2-00-16-00/dp/B01ENFOIK0/ref=sr_1_4?crid=2BPFDK0MBVZR6&dib=eyJ2IjoiMSJ9.hzSCPaykc3autVKRAm0rWl2NcYHIpIweI0R8DB9rPfqmLs7msVkGRThQL-D6TOBCtb2f6Y7Zpy3OcngiGFofEvrOSoJfD1Zhj1gHSyNIKNNZ-FB9tFXJ3btbaCvyef9pO7FuBT9UUoz1Gb0eDr87EdTgKkK-hZpfkvFCiyHfulEDXCE_P0_EX8cx9d48W_XfgBBUFKcOadHly95gDkjIM16-eJ_gqeqm-bsAah5KwAE.3FoLAfsL9dD0mIUWiAFWKuIC9g_TTi5_JRcGURK396c&dib_tag=se&keywords=Apera%2BInstruments%2BAI313%2BPH60F&qid=1725512590&sprefix=apera%2Binstruments%2Bai313%2Bph60f%2Caps%2C294&sr=8-4&th=1', 'image3', 0),
(4, 'JNW Direct Hardness Test Kit', 'Hardness', '10.99', 'Best Budget', 'Brand & Model: JNW Direct Water Hardness Test Kit\r\n\r\nResolution: 0-25 ppm increments\r\n\r\nMeasuring range: 0 to 425 ppm (0-25 grains per gallon)\r\n\r\nOperation: Simple dip-and-read testing strips\r\n\r\nPros:\r\n-Easy to use with no complicated equipment needed, just dip and read\r\n-Provides quick results within seconds\r\n-Contains 150 test strips, offering good value for frequent testing\r\n-Color chart on the bottle for easy comparison\r\n-Compact and portable, great for home or on-the-go testing\r\n-Budget-friendly price, making it accessible for regular use\r\n\r\nCons:\r\n-Not as precise as digital meters\r\n-Limited range, might not be suitable for more specific or professional testing needs\r\n-Accuracy depends on proper comparison with the color chart', 'https://www.amazon.com/JNW-Direct-Hardness-Accurate-Determine/dp/B07B31M49N/ref=sr_1_8?crid=356AKVV5HWCV&dib=eyJ2IjoiMSJ9.RmM56ihny-oxhd5xJpxch5ZU5enS-P6HhT7sHQXBMKdqTkO0X37KJuXVGdFkjptwAMo1Ww-y0LJ42E5EmlBeZmKVRM0N1zSlPavcOQHlYKxkAON_pGcP0aEEvmAuiTlzFRRgnoCOEtFdHUitO1EV63T9ppDMoLPsOD-wc6NgcCnDTamrqhkM0lvgmw4KC2TrH30aeYpzg45nbzmc3rTYC_fINXbWdMUta4g09YRx-yU.NvPjxCFxyjGyx-9aLLNEzIuIRCbiCNC5UF7VzsXMu98&dib_tag=se&keywords=water+hardness&qid=1725565744&sprefix=water+hardness%2Caps%2C341&sr=8-8', 'image4', 0),
